class KVCacheRouter:
    def __init__(self, config):
        self.minimum_cache_threshold = config.get('minimum_cache_threshold', 0.5)
        self.workers = {}

    def select_worker_by_cache_affinity(self, request_prefix_hash):
        scores = {}
        for worker_id, worker in self.workers.items():
            if not worker.is_healthy():
                continue
            score = worker.compute_cache_score(request_prefix_hash)
            scores[worker_id] = score

        if not scores:
            return None

        best_worker = max(scores, key=scores.get)
        best_score = scores[best_worker]

        if best_score < self.minimum_cache_threshold:
            return None  # BUG: should fall back, not reject

        return best_worker

    def route_request(self, request):
        prefix_hash = self.compute_prefix_hash(request)
        worker = self.select_worker_by_cache_affinity(prefix_hash)
        if worker is None:
            raise NoWorkerAvailableError('No worker with sufficient cache affinity')
        return worker
